mapper.select:
SELECT COUNT(*) > 0
FROM HC_user_holdings
WHERE user_id = #{userId}
  AND stck_shrn_iscd = #{stockCode}

mapper.update:
UPDATE HC_user_holdings
SET avg_buy_price    = (total_buy_amount + (#{quantity} * #{currentPrice})) / (total_quantity + #{quantity}),
    total_buy_amount = total_buy_amount + (#{quantity} * #{currentPrice}),
    total_quantity   = total_quantity + #{quantity}
WHERE user_id = #{userId}
  AND stck_shrn_iscd = #{stockCode}

mapper.select:
SELECT total_quantity
FROM HC_user_holdings
WHERE user_id = #{userId}
  AND stck_shrn_iscd = #{stockCode}

mapper.delete:
DELETE
FROM HC_user_holdings
WHERE user_id = #{userId}
  AND stck_shrn_iscd = #{stockCode}

mapper.update:
UPDATE HC_user_holdings
SET total_quantity   = total_quantity - #{quantity},
    total_buy_amount = total_buy_amount - (#{quantity} * #{currentPrice})
WHERE user_id = #{userId}
  AND stck_shrn_iscd = #{stockCode}

UPDATE HC_user
SET balance = balance + #{amount}
WHERE id = #{userId}
